import{_ as r,o as t,c as n,j as e,a as o,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"废土守望者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/废土守望者/废土守望者.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/废土守望者/废土守望者.md"}'),d={name:"4.资源分区/6.技艺及称号/通用及综合类/废土守望者/废土守望者.md"};function p(l,a,_,i,h,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"废土守望者",tabindex:"-1"},[o("废土守望者 "),e("a",{class:"header-anchor",href:"#废土守望者","aria-label":'Permalink to "废土守望者"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),s('<h1 id="废土守望者-1" tabindex="-1">废土守望者 <a class="header-anchor" href="#废土守望者-1" aria-label="Permalink to &quot;废土守望者&quot;">​</a></h1><p>废土守望者<br> C+1000</p><p>在无尽的辐射地区和废料堆之间，一个身影徘徊穿梭于其间。男人穿着笨重的仿佛上个世纪宇航服的防辐射衣，抱着一台聒噪的收音机在废料堆中翻找着有用的垃圾。</p><p>“I don&#39;t want to set the world on fire<br> I just want to start<br> A flame in your heart.”</p><p>男人哼唱着，用枪解决扑上来的变异生物。<br> “嘿，小子，醒醒。”<br> 你逐渐苏醒过来，只觉得头像被重锤砸过一样晕眩。你的面前有一个小型的晶体管显示器，上世纪的老玩意。显示器上是一个嬉皮笑脸的人脸，正喋喋不休着<br> “你可千万别死了，你死了的话，可没人替你收尸。”<br> 你踉跄的站起来，环顾四周。除了荒漠就是散发着辐射的废料堆。</p><p>在废土中求生，除了要做繁重的体力活之外，还要学会挨饿和忍住口渴。你在长时间与恶劣的环境进行抗争的同时也磨练了意志。现在你的强韧、意志、反射豁免各获得1DP表现加值。<br> 你逐渐学会了使用上世纪的热兵器和本世纪的武器，没有一技傍身将寸步难行。现在，在你使用所有符合条件的枪械和武器进行攻击时会获得2DP技艺加值。</p><p>废料堆里有每个废土上的垃圾佬想要的东西，辐射罐、金属、生物质能甚至是可以再次利用的生活用品。现在，你将获得可以在任何影片中翻找废料的技术，对于任何废料堆而言，你需要以一个耐力+手艺+专业：回收进行一次一个小时的延长检定，每10分钟检定一次。检定结束时根据出目决定你挖掘出东西的价值。低于或等于10时视为无价值，每上升10视为价值100点数，但一次收益最高不能超过250点数。你挖掘出的垃圾会以你希望的形式出现，共分为4种类型，分别为金属、辐射罐、生物质能、零件。每100点数的该种物品视为1组/罐（以具体为准）。当你进入任何影片后，都会随机生成数个废料堆。但每场影片，你以此法获得的收益至多不能超过1000点数。每个废料堆在翻找一次后便失去价值，不能再次翻找。</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
